import React, { useState, useEffect } from 'react';
import {
    Container,
    Typography,
    Box,
    Paper,
    Grid,
    Card,
    CardContent,
    LinearProgress,
    Button,
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
    TextField,
    MenuItem,
    IconButton,
    Alert,
    CircularProgress
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import AddIcon from '@mui/icons-material/Add';
import EditIcon from '@mui/icons-material/Edit';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import { goalsAPI } from '../services/api';

const Goals = () => {
    const [goals, setGoals] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [dialogOpen, setDialogOpen] = useState(false);
    const [deleteDialog, setDeleteDialog] = useState({ open: false, goalId: null });
    const [editingGoal, setEditingGoal] = useState(null);
    const [goalForm, setGoalForm] = useState({
        goal_type: 'weekly_workouts',
        target_value: '',
        current_value: '',
        end_date: ''
    });

    const goalTypes = [
        { value: 'weekly_workouts', label: 'Workouts per Week' },
        { value: 'total_duration', label: 'Total Duration (minutes)' },
        { value: 'total_distance', label: 'Total Distance (km)' },
        { value: 'calories_burned', label: 'Calories Burned' },
        { value: 'weight_loss', label: 'Weight Loss (kg)' },
        { value: 'strength_gain', label: 'Strength Gain' }
    ];

    useEffect(() => {
        fetchGoals();
    }, []);

    const fetchGoals = async () => {
        try {
            const response = await goalsAPI.getGoals();
            setGoals(response.data);
        } catch (err) {
            setError('Failed to load goals');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleOpenDialog = (goal = null) => {
        if (goal) {
            setEditingGoal(goal);
            setGoalForm({
                goal_type: goal.goal_type,
                target_value: goal.target_value,
                current_value: goal.current_value,
                end_date: goal.end_date ? goal.end_date.split('T')[0] : ''
            });
        } else {
            setEditingGoal(null);
            setGoalForm({
                goal_type: 'weekly_workouts',
                target_value: '',
                current_value: '',
                end_date: ''
            });
        }
        setDialogOpen(true);
    };

    const handleCloseDialog = () => {
        setDialogOpen(false);
        setEditingGoal(null);
    };

    const handleSubmit = async () => {
        try {
            const data = {
                ...goalForm,
                target_value: parseFloat(goalForm.target_value),
                current_value: parseFloat(goalForm.current_value) || 0
            };

            if (editingGoal) {
                await goalsAPI.updateGoal(editingGoal.id, data);
            } else {
                await goalsAPI.setGoal(data);
            }

            fetchGoals();
            handleCloseDialog();
        } catch (err) {
            setError(err.response?.data?.error || 'Failed to save goal');
        }
    };

    const handleDeleteClick = (goalId) => {
        setDeleteDialog({ open: true, goalId });
    };

    const handleDeleteConfirm = async () => {
        try {
            await goalsAPI.deleteGoal(deleteDialog.goalId);
            setGoals(goals.filter(goal => goal.id !== deleteDialog.goalId));
            setDeleteDialog({ open: false, goalId: null });
        } catch (err) {
            setError('Failed to delete goal');
        }
    };

    const getGoalTypeLabel = (type) => {
        const goalType = goalTypes.find(t => t.value === type);
        return goalType ? goalType.label : type;
    };

    if (loading) {
        return (
            <Container sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '80vh' }}>
                <CircularProgress />
            </Container>
        );
    }

    return (
        <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
                <Typography variant="h4">
                    Fitness Goals
                </Typography>
                <Button
                    variant="contained"
                    startIcon={<AddIcon />}
                    onClick={() => handleOpenDialog()}
                >
                    Set New Goal
                </Button>
            </Box>

            {error && (
                <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError('')}>
                    {error}
                </Alert>
            )}

            <Grid container spacing={3}>
                {goals.length === 0 ? (
                    <Grid item xs={12}>
                        <Paper sx={{ p: 4, textAlign: 'center' }}>
                            <Typography variant="h6" color="textSecondary" gutterBottom>
                                No goals set yet
                            </Typography>
                            <Typography variant="body1" color="textSecondary" sx={{ mb: 2 }}>
                                Set your first fitness goal to start tracking your progress!
                            </Typography>
                            <Button
                                variant="contained"
                                startIcon={<AddIcon />}
                                onClick={() => handleOpenDialog()}
                            >
                                Set Your First Goal
                            </Button>
                        </Paper>
                    </Grid>
                ) : (
                    goals.map((goal) => (
                        <Grid item xs={12} md={6} lg={4} key={goal.id}>
                            <Card>
                                <CardContent>
                                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 2 }}>
                                        <Box>
                                            <Typography variant="h6" component="div">
                                                {getGoalTypeLabel(goal.goal_type)}
                                            </Typography>
                                            <Typography variant="body2" color="textSecondary">
                                                Target: {goal.target_value} | Current: {goal.current_value}
                                            </Typography>
                                            {goal.end_date && (
                                                <Typography variant="caption" color="textSecondary">
                                                    Target Date: {new Date(goal.end_date).toLocaleDateString()}
                                                </Typography>
                                            )}
                                        </Box>
                                        <Box>
                                            {goal.is_completed && (
                                                <CheckCircleIcon color="success" sx={{ mr: 1 }} />
                                            )}
                                            <IconButton
                                                size="small"
                                                onClick={() => handleOpenDialog(goal)}
                                                sx={{ mr: 1 }}
                                            >
                                                <EditIcon fontSize="small" />
                                            </IconButton>
                                            <IconButton
                                                size="small"
                                                color="error"
                                                onClick={() => handleDeleteClick(goal.id)}
                                            >
                                                <DeleteIcon fontSize="small" />
                                            </IconButton>
                                        </Box>
                                    </Box>

                                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 1 }}>
                                        <Box sx={{ width: '100%', mr: 1 }}>
                                            <LinearProgress
                                                variant="determinate"
                                                value={goal.progress}
                                                color={goal.progress >= 100 ? 'success' : 'primary'}
                                            />
                                        </Box>
                                        <Box sx={{ minWidth: 35 }}>
                                            <Typography variant="body2" color="textSecondary">
                                                {Math.round(goal.progress)}%
                                            </Typography>
                                        </Box>
                                    </Box>

                                    <Typography variant="body2">
                                        {goal.is_completed ? 'Goal Completed! 🎉' : 'In Progress'}
                                    </Typography>
                                </CardContent>
                            </Card>
                        </Grid>
                    ))
                )}
            </Grid>

            {/* Add/Edit Goal Dialog */}
            <Dialog open={dialogOpen} onClose={handleCloseDialog} maxWidth="sm" fullWidth>
                <DialogTitle>
                    {editingGoal ? 'Edit Goal' : 'Set New Goal'}
                </DialogTitle>
                <DialogContent>
                    <Box sx={{ pt: 2 }}>
                        <TextField
                            select
                            fullWidth
                            label="Goal Type"
                            value={goalForm.goal_type}
                            onChange={(e) => setGoalForm({ ...goalForm, goal_type: e.target.value })}
                            margin="normal"
                        >
                            {goalTypes.map((type) => (
                                <MenuItem key={type.value} value={type.value}>
                                    {type.label}
                                </MenuItem>
                            ))}
                        </TextField>

                        <TextField
                            fullWidth
                            label="Target Value"
                            type="number"
                            value={goalForm.target_value}
                            onChange={(e) => setGoalForm({ ...goalForm, target_value: e.target.value })}
                            margin="normal"
                            required
                        />

                        <TextField
                            fullWidth
                            label="Current Value"
                            type="number"
                            value={goalForm.current_value}
                            onChange={(e) => setGoalForm({ ...goalForm, current_value: e.target.value })}
                            margin="normal"
                        />

                        <TextField
                            fullWidth
                            label="Target Date (Optional)"
                            type="date"
                            value={goalForm.end_date}
                            onChange={(e) => setGoalForm({ ...goalForm, end_date: e.target.value })}
                            margin="normal"
                            InputLabelProps={{ shrink: true }}
                        />
                    </Box>
                </DialogContent>
                <DialogActions>
                    <Button onClick={handleCloseDialog}>Cancel</Button>
                    <Button onClick={handleSubmit} variant="contained">
                        {editingGoal ? 'Update' : 'Set Goal'}
                    </Button>
                </DialogActions>
            </Dialog>

            {/* Delete Confirmation Dialog */}
            <Dialog
                open={deleteDialog.open}
                onClose={() => setDeleteDialog({ open: false, goalId: null })}
            >
                <DialogTitle>Delete Goal</DialogTitle>
                <DialogContent>
                    Are you sure you want to delete this goal? This action cannot be undone.
                </DialogContent>
                <DialogActions>
                    <Button onClick={() => setDeleteDialog({ open: false, goalId: null })}>
                        Cancel
                    </Button>
                    <Button onClick={handleDeleteConfirm} color="error" variant="contained">
                        Delete
                    </Button>
                </DialogActions>
            </Dialog>
        </Container>
    );
};

export default Goals;
